import{_ as d}from"./chunks/v2-mod-manager.B2-z5QuF.js";import{_ as a}from"./chunks/v2-mod-diff._z3eTIVk.js";import{_ as t,o as r,c as e,ag as i}from"./chunks/framework.CvgP6Fyv.js";const l="/images/v2-mod-detail.png",s="/images/v2-branch-copy.png",f=JSON.parse('{"title":"Mod 管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mod-manager.md","filePath":"guide/mod-manager.md","lastUpdated":1777473251000}'),n={name:"guide/mod-manager.md"};function p(m,o,c,M,g,h){return r(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="mod-管理" tabindex="-1">Mod 管理 <a class="header-anchor" href="#mod-管理" aria-label="Permalink to &quot;Mod 管理&quot;">​</a></h1><p>Sync the Spire 内置了 Mod 管理器，方便你安装、卸载和查看 Mod。</p><h2 id="打开-mod-管理器" tabindex="-1">打开 Mod 管理器 <a class="header-anchor" href="#打开-mod-管理器" aria-label="Permalink to &quot;打开 Mod 管理器&quot;">​</a></h2><p>在仪表盘上点击「<strong>Mod 管理</strong>」按钮即可打开 Mod 管理器。</p><p><img src="'+d+'" alt="Mod 管理器"></p><h2 id="安装-mod" tabindex="-1">安装 Mod <a class="header-anchor" href="#安装-mod" aria-label="Permalink to &quot;安装 Mod&quot;">​</a></h2><p>支持以下几种方式安装 Mod：</p><ul><li><strong>拖拽安装</strong>：将 Mod 压缩包（<code>.zip</code>、<code>.rar</code>、<code>.7z</code>）或文件夹直接拖拽到管理器窗口</li><li><strong>点击选择</strong>：点击管理器顶部的安装区域，通过文件选择器选取 Mod 压缩包</li></ul><p>安装完成后，Mod 会自动出现在列表中。</p><h2 id="查看-mod-详情" tabindex="-1">查看 Mod 详情 <a class="header-anchor" href="#查看-mod-详情" aria-label="Permalink to &quot;查看 Mod 详情&quot;">​</a></h2><p>点击任意 Mod 卡片可查看详细信息：</p><p><img src="'+l+'" alt="Mod 详情"></p><ul><li><strong>基本信息</strong>：名称、版本、作者、描述</li><li><strong>依赖关系</strong>：该 Mod 依赖的前置 Mod（✓ 绿色 = 已安装，✗ 红色 = 缺失）</li><li><strong>被依赖</strong>：哪些 Mod 依赖了它（点击可跳转）</li><li><strong>文件列表</strong>：查看 Mod 包含的文件</li></ul><div class="warning custom-block"><p class="custom-block-title">缺失前置 Mod</p><p>如果某个 Mod 依赖的前置 Mod 未安装，卡片上会显示红色警告标识。请确保安装所有必需的前置 Mod，否则游戏可能无法正常运行。</p></div><h2 id="卸载-mod" tabindex="-1">卸载 Mod <a class="header-anchor" href="#卸载-mod" aria-label="Permalink to &quot;卸载 Mod&quot;">​</a></h2><p>在 Mod 详情面板中点击「<strong>删除</strong>」按钮，确认后即可卸载该 Mod。</p><div class="danger custom-block"><p class="custom-block-title">操作不可逆</p><p>卸载会直接删除整个 Mod 文件夹，无法撤销。如果不确定，建议先备份。</p></div><h2 id="跨分支拷贝-mod" tabindex="-1">跨分支拷贝 Mod <a class="header-anchor" href="#跨分支拷贝-mod" aria-label="Permalink to &quot;跨分支拷贝 Mod&quot;">​</a></h2><p>如果你想从其他分支拷贝某个 Mod 到当前分支：</p><ol><li>点击管理器顶部的「<strong>从分支拷贝</strong>」按钮</li><li>在下拉框中选择源分支</li><li>浏览该分支的 Mod 列表，点击目标 Mod 的「<strong>拷贝</strong>」按钮</li></ol><p><img src="'+s+'" alt="从分支拷贝"></p><p>如果目标 Mod 有依赖的前置 Mod 且尚未安装，会弹出提示询问是否一并拷贝。</p><h2 id="mod-差异比较" tabindex="-1">Mod 差异比较 <a class="header-anchor" href="#mod-差异比较" aria-label="Permalink to &quot;Mod 差异比较&quot;">​</a></h2><p>在上传或拉取 Mod 时，软件会自动弹出<strong>差异预览</strong>，直观展示即将发生的变化：</p><p><img src="'+a+'" alt="Mod 差异预览"></p><ul><li>🟢 <strong>新增</strong>：此次操作新增的 Mod</li><li>🟡 <strong>更新</strong>：版本发生变化的 Mod（显示 <code>旧版本 → 新版本</code>）</li><li>🔴 <strong>移除</strong>：此次操作将移除的 Mod</li><li>无变化的 Mod 以数量汇总显示在底部</li></ul><p>确认差异后点击继续，操作才会真正执行。</p><h2 id="mod-开关" tabindex="-1">Mod 开关 <a class="header-anchor" href="#mod-开关" aria-label="Permalink to &quot;Mod 开关&quot;">​</a></h2><p>仪表盘上的「<strong>Mod 开关</strong>」可以快速切换 Mod 模式和原版模式：</p><ul><li><strong>开启</strong>：连接到 Mod 仓库，使用当前分支的 Mod</li><li><strong>关闭</strong>：断开 Mod 仓库，游戏恢复无 Mod 的原版状态</li></ul><p>Mod 文件<strong>不会被删除</strong>，只是暂时断开连接。重新打开开关即可恢复。</p>',31)])])}const q=t(n,[["render",p]]);export{f as __pageData,q as default};
